		tenncc,
		dongia,
		dongia_goc,
		--dongia_ban,
		loaitien,
		hinhanh,
		ghichu,
		kho,
		dobuc,
		solop,
		seq7,
		seg8,
		seg9,
		seq10,
		xuatxu,
		xoa,
		create_by,
		create_date,
		update_by,
		update_date,
		van_tieuchuan,
		van_mat1,
		van_mat2,
		duongkinhtrong,
		duongkinhngoai,
		heren,
		duongkinh,
		xacnhan
	)
	VALUES
	(
		@idxuong,
		@mavt,
		@tenvt,
		@tenvt_en,
		@mota,
		@quycach,
		@dayy,
		@rong,
		@dai,
		@cao,
		@dacdiem,
		@mausac,
		@dvt,
		@soluong1kg,
		@nguyenlieu,
		@nhom,
		@mancc,
		@tenncc,
		@dongia,
		@dongia_goc,
		--@dongia_ban,
		@loaitien,
		@hinhanh,
		@ghichu,
		@kho,
		@dobuc,
		@solop,
		@seq7,
		@seg8,
		@seg9,
		@seq10,
		@xuatxu,
		@xoa,
		@create_by,
		@create_date,
		@update_by,
		@update_date,
		@van_tieuchuan,
		@van_mat1,
		@van_mat2,
		@duongkinhtrong,
		@duongkinhngoai,
		@heren,
		@duongkinh,
		@xacnhan
	)

	INSERT INTO tr_material_baogia (mact, ngaytao, nguoitao, ngaysua, nguoisua)
	VALUES (@mavt, @create_date, @create_by, @update_date, @update_by);
END
